def check_parentheses_balance(expression):
    stack = []
    mapping = {")": "(", "}": "{", "]": "["}

    for char in expression:
        if char in "([{":
            stack.append(char)
        elif char in ")]}":
            if not stack:
                return False  # Kapanış parantezi ama stack boş
            top_element = stack.pop()
            if mapping[char] != top_element:
                return False  # Uyuşmayan parantez

    return not stack # Stack boşsa dengeli, değilse dengesiz
